import express from "express";
import path from "path";
import { fileURLToPath } from "url";
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = 3000;

app.use(express.json());

// Lazy-initialized Gemini AI client
let aiInstance: GoogleGenAI | null = null;
function getGeminiClient(): GoogleGenAI {
  if (!aiInstance) {
    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey) {
      throw new Error("GEMINI_API_KEY is missing. Please configure it in your Secrets settings.");
    }
    aiInstance = new GoogleGenAI({
      apiKey,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });
  }
  return aiInstance;
}

// API: Analyze student answers
app.post("/api/gemini/analyze", async (req, res) => {
  try {
    const { question, answer } = req.body;
    if (!question || !answer) {
      res.status(400).json({ error: "Missing required fields: question, answer" });
      return;
    }

    const ai = getGeminiClient();
    const prompt = `請分析以下學生的作答內容，提供回饋與學習建議。請務必使用繁體中文(台灣拼寫)回覆。
題目：
${question}

學生回答：
${answer}

請以清晰的結構（Markdown 格式）提供：
1. 【答案正確性評估】：直接指出回答是否正確或符合題意。
2. 【核心概念解析】：指出學生回答中的亮點或概念上的盲點、誤解。
3. 【AI 學習建議與加強】：給予學生具體、親切的引導，如何補強此概念或更完整地解答這類題目。`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
    });

    res.json({ analysis: response.text });
  } catch (error: any) {
    console.error("Error in /api/gemini/analyze:", error);
    res.status(500).json({ error: error.message || "Internal Server Error calling Gemini" });
  }
});

// API: Generate questions for teachers
app.post("/api/gemini/generate-questions", async (req, res) => {
  try {
    const { subject, topic, difficulty, count } = req.body;
    if (!subject || !topic || !difficulty) {
      res.status(400).json({ error: "Missing required fields: subject, topic, difficulty" });
      return;
    }

    const questionCount = Math.min(Math.max(Number(count) || 3, 1), 10);
    const ai = getGeminiClient();

    const prompt = `你是一位專業且親切的學校教師。請根據以下設定生成 ${questionCount} 題單選擇題，並提供詳細的題目解析與說明。請務必使用繁體中文(台灣拼寫)編寫。

設定條件：
- 科目：${subject}
- 學習單元/主題：${topic}
- 難易度：${difficulty} (如：易、中、難)`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.INTEGER, description: "題號，從1開始累加" },
              question: { type: Type.STRING, description: "題目敘述" },
              options: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "4個單選題選項，格式為 A.xx, B.xx, C.xx, D.xx"
              },
              answer: { type: Type.STRING, description: "正確答案選項標籤，必須為 A, B, C 或 D" },
              explanation: { type: Type.STRING, description: "詳細的題目觀念解析與正確解答說明" }
            },
            required: ["id", "question", "options", "answer", "explanation"]
          }
        }
      }
    });

    const text = response.text || "[]";
    res.json({ questions: JSON.parse(text) });
  } catch (error: any) {
    console.error("Error in /api/gemini/generate-questions:", error);
    res.status(500).json({ error: error.message || "Internal Server Error calling Gemini" });
  }
});

// Integration with Vite
async function initServer() {
  if (process.env.NODE_ENV !== "production") {
    const { createServer: createViteServer } = await import("vite");
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(__dirname, "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

initServer().catch((err) => {
  console.error("Server startup error:", err);
});
